pure fn factorial(n: Number) -> Number {
    if n <= 1 { return 1 }
    return n * factorial(n - 1)
}

entry main(x: Text) { return factorial(7) }

pure fn reverse_string(s: Text) -> Text {
    return join(reverse(split(s, "")), "")
}

entry main(x: Text) { return reverse_string("hello world") }

pure fn is_vowel(c: Text) -> Boolean {
    return c in ["a", "e", "i", "o", "u"]
}

pure fn count_vowels(s: Text) -> Number {
    total = 0
    for c in split(lower(s), "") {
        if is_vowel(c) { total = total + 1 }
    }
    return total
}

entry main(x: Text) { return count_vowels("Programming is fun") }

pure fn find_largest(numbers: List[Number]) -> Number {
    max_num = numbers[0]
    for num in numbers {
        if num > max_num { max_num = num }
    }
    return max_num
}

entry main(x: Text) {
    numbers = [34, 12, 89, 3, 56, 72]
    return find_largest(numbers)
}

pure fn sort_words(words: Text) -> Text {
    word_list = split(words, " ")
    sorted_list = sort(word_list)
    return join(sorted_list, " ")
}

entry main(x: Text) {
