pure fn is_even(n: Number) -> Boolean {
    return n % 2 == 0
}

pure fn sum_of_evens(limit: Number) -> Number {
    total = 0
    for i in range(1, limit + 1) {
        if is_even(i) { total = total + i }
    }
    return total
}

entry main(x: Text) {
    return sum_of_evens(100)
