pure fn is_palindrome(s: Text) -> Boolean {
    cleaned = lower(trim(s))
    reversed = reverse(cleaned)
    return cleaned == reversed
}

entry main(x: Text) { return is_palindrome("racecar") }

pure fn calculate_average(numbers: List[Number]) -> Number {
    total = 0
    for num in numbers {
        total = total + num
    }
    return total / length(numbers)
}

entry main(x: Text) {
    numbers = [85, 92, 78, 95, 88]
    return calculate_average(numbers)
}

pure fn remove_duplicates(list: List[Number]) -> List[Number] {
    unique_list = []
    for item in list {
        if not contains(unique_list, item) {
            unique_list = append(unique_list, item)
        }
    }
    return unique_list
}

entry main(x: Text) {
    input_list = [1, 3, 2, 3, 1, 4, 2, 5]
    return remove_duplicates(input_list)
}

pure fn count_frequency(s: Text) -> Text {
    freq = {}
    for c in split(s, "") {
        if has_key(freq, c) {
            freq[c] = freq[c] + 1
        } else {
            freq[c] = 1
        }
    }
    result = []
    for key, value in items(freq) {
        result = append(result, join([key, ": ", to_text(value)], ""))
    }
    return join(result, ", ")
}

entry main(x: Text) { return count_frequency("mississippi") }

pure fn fibonacci(n: Number) -> Number {
    if n <= 1 { return n }
    return fibonacci(n - 1) + fibonacci(n - 2)
}

entry main(x: Text) {
    results = []
    for i in range(0, 10) {
        results = append(results, to_text(fibonacci(i)))
    }
    return join(results, ", ")
}

