pure fn mean(numbers: List[Number]) -> Number {
    total = 0
    for num in numbers {
        total = total + num
    }
    return total / length(numbers)
}

pure fn variance(numbers: List[Number], m: Number) -> Number {
    total = 0
    for num in numbers {
        diff = num - m
        total = total + (diff * diff)
    }
    return total / length(numbers)
}

pure fn standard_deviation(numbers: List[Number]) -> Number {
    m = mean(numbers)
    v = variance(numbers, m)
    return sqrt(v)
}

entry main(x: Text) {
    data = [10, 12, 23, 23, 16, 23, 21, 16]
    sd = standard_deviation(data)
    explanation = if sd > mean(data) { "highly variable" } else { "not highly variable" }
    return join(["Standard Deviation: ", to_text(sd), ", Data is ", explanation], "")
}
```

**Explanation:**
- The `mean` function calculates the average of the numbers.
- The `variance` function computes the variance by summing the squared differences from the mean and dividing by the number of elements.
- The `standard_deviation` function takes the square root of the variance to get the standard deviation.
- In the `main` entry point, we calculate the standard deviation of the given data list `[10, 12, 23, 23, 16, 23, 21, 16]`.
- We then compare the standard deviation to the mean to determine if the data is highly variable. If the standard deviation is greater than the mean, the data is considered highly variable.

